// ============================================================
// State and Result Types
// ============================================================

/** SM-18 item state — persisted per learning item as JSON. */
export interface SM18State {
    /** Difficulty in [0.0, 1.0] */
    difficulty: number;
    /** Stability in days */
    stability: number;
    /** Interval in days */
    interval: number;
    /** Elapsed time since last review (days) */
    elapsed: number;
    /** Repetition count (resets on lapse) */
    repetition: number;
    /** Number of times the item was forgotten (grade < 3) */
    lapses: number;
    /** Per-grade retrievability targets (optional, defaults used if not set) */
    grade_r?: Record<number, number>;
}

/** Result of an SM-18 review computation. */
export interface SM18ReviewResult {
    /** Updated item state */
    state: SM18State;
    /** Computed retrievability before the review */
    retrievability: number;
    /** BW metric (B-W deviation for difficulty update) */
    bw: number;
    /** Computed SInc factor used */
    sinc: number;
    /** New interval in days */
    new_interval: number;
}

// ============================================================
// Helpers
// ============================================================

export function defaultSm18State(): SM18State {
    return {
        difficulty: DEFAULT_DIFFICULTY,
        stability: 0.0,
        interval: 0.0,
        elapsed: 0.0,
        repetition: 0,
        lapses: 0,
        grade_r: { ...DEFAULT_GRADE_R },
    };
}

/** Parse SM18State from JSON string, falling back to defaults. */
export function parseSm18State(algorithmState: string | undefined): SM18State {
    if (algorithmState) {
        try {
            const parsed = JSON.parse(algorithmState);
            if (parsed && typeof parsed.difficulty === 'number') {
                return {
                    difficulty: parsed.difficulty,
                    stability: parsed.stability ?? 0.0,
                    interval: parsed.interval ?? 0.0,
                    elapsed: parsed.elapsed ?? 0.0,
                    repetition: parsed.repetition ?? 0,
                    lapses: parsed.lapses ?? 0,
                    grade_r: parsed.grade_r || { ...DEFAULT_GRADE_R },
                };
            }
        } catch { /* ignore */ }
    }
    return defaultSm18State();
}

// ============================================================
// Core Functions
// ============================================================

/** Compute retrievability: R = 0.9^(t/S). R = 0.9 at t = S by definition. */
export function sm18Retrievability(stability: number, elapsedDays: number): number {
    if (stability <= 0.0) return 0.0;
    if (elapsedDays <= 0.0) return 1.0;
    return Math.pow(0.9, elapsedDays / stability);
}

/** Compute interval from stability: S * ln(1-FI) / ln(0.9). For FI = 0.10, interval == stability. */
export function sm18IntervalFromStability(stability: number, fi: number): number {
    if (stability <= 0.0 || fi <= 0.0 || fi >= 1.0) return 0.0;
    if (Math.abs(fi - 0.10) < 1e-9) return stability;
    return stability * Math.log(1.0 - fi) / Math.log(0.9);
}

/** Compute BW (B-W deviation) metric. BW = (grade_R - R) for success, -R for failure. */
function computeBw(grade: number, r: number, gradeR: number): number {
    if (grade >= SUCCESS_GRADE) {
        return gradeR - r;
    }
    return -r;
}

/** Convert BW to difficulty: BW=+0.1 -> D=0.0, BW=-0.9 -> D=1.0. */
function bwToDifficulty(bw: number): number {
    const d = 0.1 - bw;
    return Math.max(0.0, Math.min(1.0, d));
}

/** Update difficulty using trailing average. D_new = f * RepDiff + (1-f) * D_old */
function updateDifficulty(dOld: number, bw: number, repNo: number): number {
    const repDiff = bwToDifficulty(bw);
    const f = Math.max(0.10, 0.80 - Math.max(0, repNo - 1) * 0.06);
    return Math.max(0.0, Math.min(1.0, f * repDiff + (1.0 - f) * dOld));
}

/** Map stability S to S-grade [1, 20] using log-spaced boundaries. */
function binSGrade(s: number): number {
    if (s <= 0.0) return 1;
    if (s <= DEFAULT_S_BOUNDARIES[0]) return 1;
    for (let i = 0; i < DEFAULT_S_BOUNDARIES.length - 1; i++) {
        if (s <= DEFAULT_S_BOUNDARIES[i + 1]) return i + 2;
    }
    return 20;
}

/** Map difficulty D in [0.0, 1.0] to D-grade [1, 20]. */
function binDGrade(d: number): number {
    const grade = Math.floor(d * 19.0) + 1;
    return Math.max(1, Math.min(20, grade));
}

/** Map retrievability R in (0.0, 1.0] to R-grade [1, 20]. */
function binRGrade(r: number): number {
    if (r >= 1.0) return 1;
    const oneMinusR = 1.0 - r;
    const grade = Math.floor(oneMinusR * 19.0) + 1;
    return Math.max(1, Math.min(20, grade));
}

/**
 * Look up SInc from the default matrix (StabilityIncrease.dat).
 * Falls back to DEFAULT_SINC (0.07) for sentinel/zero entries.
 */
function sincLookup(dGrade: number, sGrade: number, rGrade: number): number {
    const dIdx = Math.min(Math.max(dGrade - 1, 0), 19);
    const sIdx = Math.min(Math.max(sGrade - 1, 0), 19);
    const rIdx = Math.min(Math.max(rGrade - 1, 0), 19);

    const flatIdx = dIdx * 441 + sIdx * 21 + rIdx;
    if (flatIdx < SINC_MATRIX.length && SINC_MATRIX[flatIdx] > 0.0) {
        return SINC_MATRIX[flatIdx];
    }

    return DEFAULT_SINC;
}

/** Get grade-to-retrievability mapping for a given grade. */
function getGradeR(state: SM18State, grade: number): number {
    if (state.grade_r && state.grade_r[grade] !== undefined) {
        return state.grade_r[grade];
    }
    return DEFAULT_GRADE_R[grade] ?? 0.9;
}

// ============================================================
// Review Function
// ============================================================

/**
 * Process an SM-18 review and update item state.
 *
 * @param state - Current SM-18 item state (mutated in place)
 * @param grade - Review grade (0-5: 0=complete blackout, 3=good, 5=perfect)
 * @param elapsedDays - Time since last review in days
 * @param fi - Forgetting index (default: 0.10 = 10%)
 * @returns Review result with updated state and computed metrics.
 */
export function sm18Review(
    state: SM18State,
    grade: number,
    elapsedDays: number,
    fi: number = DEFAULT_FI,
): SM18ReviewResult {
    fi = fi <= 0.0 ? DEFAULT_FI : fi;

    // Step 1: Compute retrievability
    let r: number;
    if (state.stability > 0.0 && elapsedDays > 0.0) {
        r = sm18Retrievability(state.stability, elapsedDays);
    } else {
        r = 1.0;
    }
    r = Math.max(0.0, Math.min(1.0, r));

    // Step 2: Get grade-to-R mapping
    const gradeR = getGradeR(state, grade);

    // Step 3: Compute BW
    const bw = computeBw(grade, r, gradeR);

    let sinc = 0.0;

    if (grade < SUCCESS_GRADE) {
        // === FAILURE PATH ===
        state.lapses += 1;
        state.stability = Math.max(
            state.stability * POST_LAPSE_STABILITY_MOD / (1.0 + 0.1 * state.lapses),
            0.5,
        );
        state.interval = Math.max(POST_LAPSE_INTERVAL, 1.0);
        state.repetition = 0;
    } else {
        // === SUCCESS PATH ===
        state.repetition += 1;

        if (state.repetition === 1 && state.stability <= 0.0) {
            // First successful review of a new item — matches Python reference
            state.stability = STARTUP_STABILITY;
            state.interval = STARTUP_INTERVAL;
        } else {
            // Compute bin indices
            const dGrade = binDGrade(state.difficulty);
            const sGrade = binSGrade(state.stability);
            const rGrade = binRGrade(r);

            // Look up SInc
            sinc = sincLookup(dGrade, sGrade, rGrade);

            // Update stability: S_new = S_old * SInc
            if (sinc > 0.0) {
                state.stability = state.stability * sinc;
            }

            // Compute new interval
            state.interval = sm18IntervalFromStability(state.stability, fi);
        }
    }

    // Step 4: Update difficulty (only for grades within valid range)
    if (grade >= 0 && grade <= 5) {
        state.difficulty = updateDifficulty(state.difficulty, bw, state.repetition);
    }

    state.elapsed = 0.0;

    return {
        state,
        retrievability: r,
        bw,
        sinc,
        new_interval: state.interval,
    };
}

/**
 * Map Tauri review ratings (0=Again, 1=Hard, 2=Good, 3=Easy) to SM-18 grades (0-5).
 * Again->0, Hard->2, Good->3, Easy->5 (matches Rust review.rs mapping).
 */
export function ratingToSm18Grade(rating: number): number {
    switch (rating) {
        case 0: return 0; // Again
        case 1: return 2; // Hard
        case 2: return 3; // Good
        case 3: return 5; // Easy
        default: return 3;
    }
}
